-- CNB Preprimaria (vigente desde 2023) - cnbguatemala.org/wiki/CNB_Preprimaria
-- 5 áreas curriculares x competencias por Párvulos 1, 2 y 3
-- grado usa la etiqueta literal 'Párvulos 1' / 'Párvulos 2' / 'Párvulos 3'

INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES

-- Área: Educación para la Ciencia y la Ciudadanía
('Párvulos 1', 'Educación para la Ciencia y la Ciudadanía', 'Interviene en el cuidado del ambiente como parte de su identidad y pertenencia al entorno. Coopera en el cuidado del ambiente en sus actividades cotidianas como resultado de su identificación con el entorno.', ARRAY['Coopera en el cuidado del ambiente en sus actividades cotidianas como resultado de su identificación con el entorno.']),
('Párvulos 2', 'Educación para la Ciencia y la Ciudadanía', 'Interviene en el cuidado del ambiente como parte de su identidad y pertenencia al entorno. Muestra iniciativa para el cuidado ambiental en los contextos que frecuenta, con los cuales se siente identificado y relacionado.', ARRAY['Muestra iniciativa para el cuidado ambiental en los contextos que frecuenta, con los cuales se siente identificado y relacionado.']),
('Párvulos 3', 'Educación para la Ciencia y la Ciudadanía', 'Interviene en el cuidado del ambiente como parte de su identidad y pertenencia al entorno. Participa en el cuidado del ambiente de la comunidad con la cual comparte vínculos de cotidianidad, identidad y pertenencia.', ARRAY['Participa en el cuidado del ambiente de la comunidad con la cual comparte vínculos de cotidianidad, identidad y pertenencia.']),

('Párvulos 1', 'Educación para la Ciencia y la Ciudadanía', 'Establece relaciones saludables basadas en el respeto, la valoración de sí mismo y de los demás. Expresa aprecio y buen trato consigo mismo y con otros, en su entorno.', ARRAY['Expresa aprecio y buen trato consigo mismo y con otros, en su entorno.']),
('Párvulos 2', 'Educación para la Ciencia y la Ciudadanía', 'Establece relaciones saludables basadas en el respeto, la valoración de sí mismo y de los demás. Manifiesta estima de sí mismo y hacia los demás en diferentes contextos.', ARRAY['Manifiesta estima de sí mismo y hacia los demás en diferentes contextos.']),
('Párvulos 3', 'Educación para la Ciencia y la Ciudadanía', 'Establece relaciones saludables basadas en el respeto, la valoración de sí mismo y de los demás. Establece relaciones saludables individuales y colectivas, a partir de la valoración de sí mismo, en diferentes contextos.', ARRAY['Establece relaciones saludables individuales y colectivas, a partir de la valoración de sí mismo, en diferentes contextos.']),

('Párvulos 1', 'Educación para la Ciencia y la Ciudadanía', 'Resuelve situaciones de su entorno mediante procedimientos científicos simples, tecnología y otros recursos a su alcance. Reconoce herramientas, recursos y procedimientos básicos para desarrollar una actividad.', ARRAY['Reconoce herramientas, recursos y procedimientos básicos para desarrollar una actividad.']),
('Párvulos 2', 'Educación para la Ciencia y la Ciudadanía', 'Resuelve situaciones de su entorno mediante procedimientos científicos simples, tecnología y otros recursos a su alcance. Resuelve situaciones cotidianas utilizando herramientas, recursos y procedimientos científicos simples.', ARRAY['Resuelve situaciones cotidianas utilizando herramientas, recursos y procedimientos científicos simples.']),
('Párvulos 3', 'Educación para la Ciencia y la Ciudadanía', 'Resuelve situaciones de su entorno mediante procedimientos científicos simples, tecnología y otros recursos a su alcance. Aplica procedimientos científicos simples, tecnología y otros recursos para resolver situaciones de su contexto.', ARRAY['Aplica procedimientos científicos simples, tecnología y otros recursos para resolver situaciones de su contexto.']),

-- Área: Destrezas de Comunicación y Lenguaje
('Párvulos 1', 'Destrezas de Comunicación y Lenguaje', 'Se comunica en su idioma materno, en diferentes contextos, según su desarrollo y conocimientos. Se comunica en forma oral o lengua de señas, según su idioma materno, en situaciones y contextos conocidos.', ARRAY['Se comunica en forma oral o lengua de señas, según su idioma materno, en situaciones y contextos conocidos.']),
('Párvulos 2', 'Destrezas de Comunicación y Lenguaje', 'Se comunica en su idioma materno, en diferentes contextos, según su desarrollo y conocimientos. Se comunica en forma oral o lengua de señas, según su idioma materno, en situaciones y contextos más variados, con seguridad.', ARRAY['Se comunica en forma oral o lengua de señas, según su idioma materno, en situaciones y contextos más variados, con seguridad.']),
('Párvulos 3', 'Destrezas de Comunicación y Lenguaje', 'Se comunica en su idioma materno, en diferentes contextos, según su desarrollo y conocimientos. Se comunica en forma oral o lengua de señas, según su idioma materno, en situaciones y contextos diversos, con mayor autonomía (iniciativa, libertad de decisión).', ARRAY['Se comunica en forma oral o lengua de señas, según su idioma materno, en situaciones y contextos diversos, con mayor autonomía (iniciativa, libertad de decisión).']),

('Párvulos 1', 'Destrezas de Comunicación y Lenguaje', 'Lee de manera emergente en su idioma materno, de acuerdo con su etapa de vida y desarrollo. Desarrolla habilidades de lectura emergente, acorde con su edad y proceso evolutivo.', ARRAY['Desarrolla habilidades de lectura emergente, acorde con su edad y proceso evolutivo.']),
('Párvulos 2', 'Destrezas de Comunicación y Lenguaje', 'Lee de manera emergente en su idioma materno, de acuerdo con su etapa de vida y desarrollo. Desarrolla habilidades de lectura emergente según su edad, proceso evolutivo y formación educativa previa.', ARRAY['Desarrolla habilidades de lectura emergente según su edad, proceso evolutivo y formación educativa previa.']),
('Párvulos 3', 'Destrezas de Comunicación y Lenguaje', 'Lee de manera emergente en su idioma materno, de acuerdo con su etapa de vida y desarrollo. Desarrolla habilidades de lectura emergente en forma autónoma según su edad, proceso evolutivo y formación educativa previa.', ARRAY['Desarrolla habilidades de lectura emergente en forma autónoma según su edad, proceso evolutivo y formación educativa previa.']),

('Párvulos 1', 'Destrezas de Comunicación y Lenguaje', 'Produce distintos tipos de textos de manera emergente, en su idioma materno. Produce textos en forma emergente, acorde con su edad y proceso evolutivo.', ARRAY['Produce textos en forma emergente, acorde con su edad y proceso evolutivo.']),
('Párvulos 2', 'Destrezas de Comunicación y Lenguaje', 'Produce distintos tipos de textos de manera emergente, en su idioma materno. Produce textos en forma emergente, acorde con su edad, proceso evolutivo y formación educativa previa.', ARRAY['Produce textos en forma emergente, acorde con su edad, proceso evolutivo y formación educativa previa.']),
('Párvulos 3', 'Destrezas de Comunicación y Lenguaje', 'Produce distintos tipos de textos de manera emergente, en su idioma materno. Produce textos en forma emergente, acorde con su edad, proceso evolutivo, formación educativa previa y sus propios intereses.', ARRAY['Produce textos en forma emergente, acorde con su edad, proceso evolutivo, formación educativa previa y sus propios intereses.']),

-- Área: Destrezas de Aprendizaje Matemático
('Párvulos 1', 'Destrezas de Aprendizaje Matemático', 'Establece relaciones de forma, espacio, tiempo y cantidad, a partir de información que obtiene del entorno, para tomar decisiones propias de su etapa de vida. Establece relaciones entre actividades y el tiempo; objetos y forma, cantidad y espacio, tomando como referencia su cuerpo y elementos de su entorno.', ARRAY['Establece relaciones entre actividades y el tiempo; objetos y forma, cantidad y espacio, tomando como referencia su cuerpo y elementos de su entorno.']),
('Párvulos 2', 'Destrezas de Aprendizaje Matemático', 'Establece relaciones de forma, espacio, tiempo y cantidad, a partir de información que obtiene del entorno, para tomar decisiones propias de su etapa de vida. Determina relaciones espaciales, temporales, de cantidad y atributos, cambiando de referencias para interactuar con el contexto.', ARRAY['Determina relaciones espaciales, temporales, de cantidad y atributos, cambiando de referencias para interactuar con el contexto.']),
('Párvulos 3', 'Destrezas de Aprendizaje Matemático', 'Establece relaciones de forma, espacio, tiempo y cantidad, a partir de información que obtiene del entorno, para tomar decisiones propias de su etapa de vida. Utiliza la forma, atributos, posiciones espaciales, nociones temporales y de cantidad de los elementos para comparar de forma lógica a partir de dos o más referencias.', ARRAY['Utiliza la forma, atributos, posiciones espaciales, nociones temporales y de cantidad de los elementos para comparar de forma lógica a partir de dos o más referencias.']),

('Párvulos 1', 'Destrezas de Aprendizaje Matemático', 'Genera el pensamiento científico y creativo, a partir de la comprensión del entorno, para resolver situaciones de su cotidianidad. Utiliza pensamiento científico y creativo que favorecen la comprensión de su entorno y le permiten expresarse.', ARRAY['Utiliza pensamiento científico y creativo que favorecen la comprensión de su entorno y le permiten expresarse.']),
('Párvulos 2', 'Destrezas de Aprendizaje Matemático', 'Genera el pensamiento científico y creativo, a partir de la comprensión del entorno, para resolver situaciones de su cotidianidad. Establece procesos que implican un pensamiento científico y creativo para resolver situaciones cotidianas.', ARRAY['Establece procesos que implican un pensamiento científico y creativo para resolver situaciones cotidianas.']),
('Párvulos 3', 'Destrezas de Aprendizaje Matemático', 'Genera el pensamiento científico y creativo, a partir de la comprensión del entorno, para resolver situaciones de su cotidianidad. Emplea el pensamiento científico y creativo para verificar procesos y resolver situaciones cotidianas.', ARRAY['Emplea el pensamiento científico y creativo para verificar procesos y resolver situaciones cotidianas.']),

-- Área: Educación Artística
('Párvulos 1', 'Educación Artística', 'Competencia 1 (ritmo/expresión sonora). Realiza ejercicios de ritmo auditivo guiados, con diferentes fuentes sonoras de su entorno.', ARRAY['Realiza ejercicios de ritmo auditivo guiados, con diferentes fuentes sonoras de su entorno.']),
('Párvulos 2', 'Educación Artística', 'Competencia 1 (ritmo/expresión sonora). Produce ritmos musicales que percibe de diferentes fuentes de su entorno.', ARRAY['Produce ritmos musicales que percibe de diferentes fuentes de su entorno.']),
('Párvulos 3', 'Educación Artística', 'Competencia 1 (ritmo/expresión sonora). Ejecuta ritmos de su entorno utilizándolos en expresiones cotidianas.', ARRAY['Ejecuta ritmos de su entorno utilizándolos en expresiones cotidianas.']),

('Párvulos 1', 'Educación Artística', 'Competencia 2 (exploración sonora e instrumental). Experimenta sonidos con su cuerpo y voz, útiles sonoros e instrumentos musicales dentro de ensambles sonoros o musicales.', ARRAY['Experimenta sonidos con su cuerpo y voz, útiles sonoros e instrumentos musicales dentro de ensambles sonoros o musicales.']),
('Párvulos 2', 'Educación Artística', 'Competencia 2 (exploración sonora e instrumental). Reproduce música con diferentes formas de producción sonora como su cuerpo y su voz, útiles sonoros e instrumentos musicales que tiene a su alcance para explorar todas sus posibilidades.', ARRAY['Reproduce música con diferentes formas de producción sonora como su cuerpo y su voz, útiles sonoros e instrumentos musicales que tiene a su alcance para explorar todas sus posibilidades.']),
('Párvulos 3', 'Educación Artística', 'Competencia 2 (exploración sonora e instrumental). Interpreta ritmos y melodías sencillas individual y grupalmente.', ARRAY['Interpreta ritmos y melodías sencillas individual y grupalmente.']),

('Párvulos 1', 'Educación Artística', 'Competencia 3 (reconocimiento de paisajes sonoros). Identifica sonidos de su alrededor.', ARRAY['Identifica sonidos de su alrededor.']),
('Párvulos 2', 'Educación Artística', 'Competencia 3 (reconocimiento de paisajes sonoros). Reconoce paisajes sonoros de su contexto.', ARRAY['Reconoce paisajes sonoros de su contexto.']),
('Párvulos 3', 'Educación Artística', 'Competencia 3 (reconocimiento de paisajes sonoros). Reproduce sonidos y paisajes sonoros de su entorno.', ARRAY['Reproduce sonidos y paisajes sonoros de su entorno.']),

-- Área: Educación Física
('Párvulos 1', 'Educación Física', 'Domina habilidades motoras básicas que le permiten organizar y estructurar su acción motora en diferentes contextos. Desarrolla habilidades motrices a partir de sus posibilidades y funciones corporales.', ARRAY['Desarrolla habilidades motrices a partir de sus posibilidades y funciones corporales.']),
('Párvulos 2', 'Educación Física', 'Domina habilidades motoras básicas que le permiten organizar y estructurar su acción motora en diferentes contextos. Realiza acciones motoras de forma organizada, en diferentes contextos y circunstancias, de acuerdo a sus posibilidades.', ARRAY['Realiza acciones motoras de forma organizada, en diferentes contextos y circunstancias, de acuerdo a sus posibilidades.']),
('Párvulos 3', 'Educación Física', 'Domina habilidades motoras básicas que le permiten organizar y estructurar su acción motora en diferentes contextos. Coordina esquemas motrices de manera estructurada y autónoma en diferentes situaciones y contextos, de acuerdo con sus posibilidades.', ARRAY['Coordina esquemas motrices de manera estructurada y autónoma en diferentes situaciones y contextos, de acuerdo con sus posibilidades.']),

('Párvulos 1', 'Educación Física', 'Establece relaciones sociales positivas y autorregula sus emociones, de manera progresiva, en las actividades motrices grupales y colaborativas. Expresa sus emociones en diferentes contextos y acciones motrices.', ARRAY['Expresa sus emociones en diferentes contextos y acciones motrices.']),
('Párvulos 2', 'Educación Física', 'Establece relaciones sociales positivas y autorregula sus emociones, de manera progresiva, en las actividades motrices grupales y colaborativas. Desarrolla habilidades emocionales que facilitan su interacción con otros en diferentes contextos y actividades motrices.', ARRAY['Desarrolla habilidades emocionales que facilitan su interacción con otros en diferentes contextos y actividades motrices.']),
('Párvulos 3', 'Educación Física', 'Establece relaciones sociales positivas y autorregula sus emociones, de manera progresiva, en las actividades motrices grupales y colaborativas. Autorregula sus emociones al interactuar de forma progresiva a la etapa de desarrollo.', ARRAY['Autorregula sus emociones al interactuar de forma progresiva a la etapa de desarrollo.']),

('Párvulos 1', 'Educación Física', 'Practica hábitos de higiene, alimentarios y de actividad física que favorecen su desarrollo integral y mejoran su calidad de vida. Realiza rutinas de higiene, actividades físicas y hábitos alimentarios de manera guiada en beneficio de una vida saludable.', ARRAY['Realiza rutinas de higiene, actividades físicas y hábitos alimentarios de manera guiada en beneficio de una vida saludable.']),
('Párvulos 2', 'Educación Física', 'Practica hábitos de higiene, alimentarios y de actividad física que favorecen su desarrollo integral y mejoran su calidad de vida. Practica actividad física, hábitos higiénicos y alimentarios que favorecen su desarrollo integral.', ARRAY['Practica actividad física, hábitos higiénicos y alimentarios que favorecen su desarrollo integral.']),
('Párvulos 3', 'Educación Física', 'Practica hábitos de higiene, alimentarios y de actividad física que favorecen su desarrollo integral y mejoran su calidad de vida. Practica con autonomía rutinas de hábitos higiénicos, alimentarios y de actividad física que le permiten mejorar su calidad de vida.', ARRAY['Practica con autonomía rutinas de hábitos higiénicos, alimentarios y de actividad física que le permiten mejorar su calidad de vida.']);
